const STREAMED_API_BASE = process.env.NEXT_PUBLIC_STREAMED_API_BASE_URL || 'https://streamed.pk/api'

// API ID MAP
const SPORT_ID_MAP: Record<string, string> = {
  "1": "Football", "2": "Basketball", "3": "Cricket", "4": "Tennis", "5": "Rugby", 
  "6": "Ice Hockey", "7": "American Football", "8": "Baseball", "9": "Motorsport", 
  "10": "Fighting", "12": "Volleyball"
};

function getBadgeUrl(badgeId: string | undefined): string {
  if (!badgeId) return '/placeholder-badge.webp' 
  return `${STREAMED_API_BASE}/images/badge/${badgeId}.webp`
}

function getCardShade(matchId: string): string {
  let hash = 0;
  for (let i = 0; i < matchId.length; i++) {
    hash = matchId.charCodeAt(i) + ((hash << 5) - hash);
  }
  const seed = (Math.abs(hash) % 15) + 1;
  return `card-shade-${seed}`;
}

interface Match {
  id: string; title?: string; date?: string; competition?: string; category?: string;
  teams?: { home?: { name?: string; badge?: string }; away?: { name?: string; badge?: string }; };
  sources?: any[];
}

export default function MatchesList() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { t, lang } = useLanguage();

  const sportId = searchParams.get("sportId");
  const rawSportName = searchParams.get("sportName") || (sportId ? SPORT_ID_MAP[sportId] : "Matches") || "Matches";
  const displaySportName = rawSportName === "Matches" ? t.matches_fallback : rawSportName;

  const [matches, setMatches] = useState<Match[]>([]);
  const [filteredMatches, setFilteredMatches] = useState<Match[]>([]);
  const [filter, setFilter] = useState("live"); 
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  // 🔥 SIMPLIFIED SPORTS LIST (Matches your component)
  const sportsList = [
    { label: t.filter_all, id: null, name: 'Matches' },
    { label: t.soccer, id: '1', name: 'Football' },
    { label: t.nba, id: '2', name: 'Basketball' },
    { label: t.nfl, id: '7', name: 'American Football' },
    { label: t.cricket, id: '3', name: 'Cricket' },
    { label: t.f1, id: '9', name: 'Motorsport' },
    { label: t.mma, id: '10', name: 'Fighting' },
    { label: t.tennis, id: '4', name: 'Tennis' },
    { label: t.rugby, id: '5', name: 'Rugby' },
  ];

  useEffect(() => {
    let isMounted = true;
    async function fetchMatches() {
      try {
        setLoading(true);
        setError(false);
        const url = sportId ? `${STREAMED_API_BASE}/matches/${sportId}` : `${STREAMED_API_BASE}/matches/all-today`;
        
        const res = await fetch(url, { cache: 'no-store' });
        if (!res.ok) throw new Error("API_ERROR");
        const data = await res.json();
        const dataArray = Array.isArray(data) ? data : [];
        const validMatches = dataArray; 

        validMatches.sort((a, b) => (a.date ? new Date(a.date).getTime() : 0) - (b.date ? new Date(b.date).getTime() : 0));
        
        if (isMounted) setMatches(validMatches);
      } catch (err) {
        console.error(err);
        if (isMounted) setError(true);
      } finally {
        if (isMounted) setLoading(false);
      }
    }
    fetchMatches();
    return () => { isMounted = false; };
  }, [sportId]);

  useEffect(() => {
    const now = new Date(); 
    const result = matches.filter(match => {
        if (!match.date) return filter === "all"; 
        const matchDate = new Date(match.date);
        
        const isLive = matchDate <= now && matchDate >= new Date(now.getTime() - 4 * 60 * 60 * 1000);
        const isUpcoming = matchDate > now;

        if (filter === 'all') return true; 
        if (filter === 'upcoming') return isUpcoming;
        if (filter === 'live') return isLive;
        return false;
    });
    setFilteredMatches(result);
  }, [filter, matches]);

  const grouped = filteredMatches.reduce((acc, match) => {
      if (!match.date) return acc;
      const d = new Date(match.date);
      if (isNaN(d.getTime())) return acc;
      const dateKey = d.toLocaleDateString(lang === 'ur' ? 'en-US' : lang, { weekday: 'short', month: 'short', day: 'numeric' });
      if (!acc[dateKey]) acc[dateKey] = [];
      acc[dateKey].push(match);
      return acc;
  }, {} as Record<string, Match[]>);

  // 🔥 HANDLE SPORT CHANGE
  const handleSportClick = (item: { id: string | null; name: string }) => {
     if (item.id) {
       router.push(`/live-matches?sportId=${item.id}&sportName=${encodeURIComponent(item.name)}`)
     } else {
       router.push(`/live-matches`)
     }
  }

  // --- STYLES ---
  const s = {
    container: { width: '100%', maxWidth: '1400px', margin: '0 auto', padding: '20px', minHeight: '100vh', position: 'relative' as const, zIndex: 10 },
    headerWrapper: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px', borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '15px', flexWrap: 'wrap' as const, gap: '15px', position: 'relative' as const, zIndex: 50 },
    titleGroup: { display: 'flex', alignItems: 'center', gap: '15px' },
    titleText: { fontSize: '24px', fontWeight: 900, color: '#fff', textTransform: 'uppercase' as const, margin: 0, display: 'flex', alignItems: 'center', gap: '12px', lineHeight: 1 },
    greenBar: { width: '4px', height: '24px', background: '#8db902', borderRadius: '2px' },
    homeLink: { display: 'flex', alignItems: 'center', gap: '6px', color: '#888', fontSize: '12px', fontWeight: 600, textTransform: 'uppercase' as const, textDecoration: 'none' },
    filterBar: { display: 'flex', gap: '10px', marginBottom: '20px', flexWrap: 'wrap' as const, position: 'relative' as const, zIndex: 50 },
    btn: (active: boolean) => ({
        padding: '10px 24px', borderRadius: '6px', fontSize: '12px', fontWeight: active ? 800 : 600, textTransform: 'uppercase' as const, letterSpacing: '0.5px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'all 0.2s ease', minWidth: '100px',
        background: active ? '#8db902' : 'transparent', color: active ? '#000' : '#ffffff', border: active ? '1px solid #8db902' : '1px solid #ffffff', boxShadow: active ? '0 0 10px rgba(141, 185, 2, 0.4)' : 'none'
    }),
    grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '15px' },
    card: { background: '#050505', border: '1px solid #1a1a1a', borderRadius: '10px', padding: '12px', display: 'flex', flexDirection: 'column' as const, position: 'relative' as const, overflow: 'hidden', minHeight: '110px' },
    matchSkeletonCard: { background: 'linear-gradient(to right, #161920 4%, #20242e 25%, #161920 36%)', backgroundSize: '1000px 100%', animation: 'shimmer 2s infinite linear', borderRadius: '10px', border: '1px solid #222', height: '110px', width: '100%' },
    shimmer: { background: 'linear-gradient(to right, #161920 4%, #20242e 25%, #161920 36%)', backgroundSize: '1000px 100%', animation: 'shimmer 2s infinite linear' }
  };

  const PageWrapper = ({ children }: { children: React.ReactNode }) => (
    <>
        <style dangerouslySetInnerHTML={{ __html: globalCss }} />
        <div className="snow-wrapper"><div className="snow-layer layer-1"></div><div className="snow-layer layer-2"></div><div className="snow-layer layer-3"></div></div>
        <Header />
        <div style={s.container}>{children}</div>
    </>
  );

  if (loading) return ( 
    <PageWrapper>
      <div style={s.headerWrapper}>
        <div style={{display: 'flex', gap: '15px', alignItems: 'center'}}>
           <div style={{width:'4px', height:'24px', background:'#222', borderRadius:'2px'}}></div>
           <div style={{...s.shimmer, width: '200px', height: '30px', borderRadius: '4px'}}></div>
        </div>
        <div style={{...s.shimmer, width: '120px', height: '20px', borderRadius: '4px'}}></div>
      </div>
      <div className="filters-section">
         <div className="filters-bar">
            <div style={{...s.shimmer, width: '100%', height: '40px', borderRadius: '6px'}}></div>
         </div>
      </div>
      <div style={s.grid}>{[...Array(12)].map((_, i) => <div key={i} style={s.matchSkeletonCard}></div>)}</div>
    </PageWrapper> 
  )

  if (error) return ( <PageWrapper><div style={{textAlign:'center', color:'#ff4444'}}>{t.server_error} <button onClick={() => window.location.reload()}>Retry</button></div></PageWrapper> )

  return (
    <PageWrapper>
        <div style={s.headerWrapper}>
            <div style={s.titleGroup}><h1 style={s.titleText}><span style={s.greenBar}></span>{displaySportName}</h1></div>
            <Link href="/" style={s.homeLink}>{t.back_to_home} <ArrowUpRight size={14} /></Link>
        </div>
        
        {/* 🔥 NEW SPORTS FILTER BAR (Integrated Here) */}
        <div className="filters-section">
          <div className="filters-bar">
            <div className="sports-scroll-area">
              {sportsList.map((item) => (
                <button
                  key={item.name}
                  className={`filter-pill ${(!sportId && !item.id) || (sportId === item.id) ? 'active' : ''}`}
                  onClick={() => handleSportClick(item)}
                >
                  {item.label}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* TIME FILTER BAR */}
        <div style={s.filterBar}>
            <button style={s.btn(filter === 'live')} onClick={() => setFilter('live')}>{t.live}</button>
            <button style={s.btn(filter === 'upcoming')} onClick={() => setFilter('upcoming')}>{t.upcoming}</button>
            <button style={s.btn(filter === 'all')} onClick={() => setFilter('all')}>{t.filter_all}</button>
        </div>

        {Object.keys(grouped).length === 0 ? (
            <div style={{ textAlign: 'center', padding: '60px 20px', color: '#666' }}>
                <div style={{fontSize: '16px', fontWeight: 'bold', color: '#fff'}}>
                    {filter === 'live' ? t.no_live_matches : t.no_matches_found}
                </div>
            </div>
        ) : (
            Object.entries(grouped).map(([date, dateMatches]) => (
                <div key={date}>
                    <div style={{display:'flex', alignItems:'center', gap:'10px', margin:'30px 0 15px 0', color:'#fff'}}>
                        <Calendar size={16} color="#8db902" />
                        <span style={{fontWeight:700, fontSize:'14px', textTransform:'uppercase'}}>{date}</span>
                        <div style={{flex:1, height:'1px', background:'linear-gradient(90deg, #8db902 0%, rgba(255,255,255,0.05) 100%)'}}></div>
                    </div>
                    <div style={s.grid}>
                        {dateMatches.map(match => {
                            const now = new Date();
                            const mDate = new Date(match.date!);
                            const isLive = mDate <= now && mDate >= new Date(now.getTime() - 4 * 60 * 60 * 1000);
                            const shade = getCardShade(match.id);
                            const bgStyle = shade.includes('1') ? 'repeating-linear-gradient(45deg, #050505, #050505 10px, #0d0d0d 10px, #0d0d0d 20px)' : '#050505';

                            return (
                                <Link 
                                    key={match.id} 
                                    href={`/match/${match.id}?sportName=${encodeURIComponent(displaySportName)}`}
                                    style={{textDecoration:'none', display:'block'}}
                                    onClick={() => {
                                        sessionStorage.setItem("currentMatch", JSON.stringify({
                                            ...match, 
                                            id: String(match.id)
                                        }));
                                    }}
                                >
                                    <div style={{...s.card, background: bgStyle}}>
                                        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'8px' }}>
                                            <div style={{display:'flex', flexDirection:'column', alignItems:'center', width:'40%'}}>
                                                <img src={getBadgeUrl(match.teams?.home?.badge)} style={{width:'32px', height:'32px', objectFit:'contain'}} alt="Home" />
                                                <span style={{fontSize:'11px', color:'#eee', marginTop:'4px', fontWeight:600}}>{match.teams?.home?.name || t.team_home}</span>
                                            </div>
                                            
                                            <div style={{fontSize:'10px', fontWeight:900, color:'#444', fontStyle:'italic'}}>{t.vs_badge}</div>
                                            
                                            <div style={{display:'flex', flexDirection:'column', alignItems:'center', width:'40%'}}>
                                                <img src={getBadgeUrl(match.teams?.away?.badge)} style={{width:'32px', height:'32px', objectFit:'contain'}} alt="Away" />
                                                <span style={{fontSize:'11px', color:'#eee', marginTop:'4px', fontWeight:600}}>{match.teams?.away?.name || t.team_away}</span>
                                            </div>
                                        </div>
                                        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', borderTop:'1px solid #222', paddingTop:'8px', marginTop:'auto' }}>
                                            <div style={{fontSize:'11px', color:'#fff', whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis', maxWidth:'65%'}}>{match.title || match.competition || 'Match'}</div>
                                            <div>
                                                {isLive ? (
                                                    <span style={{background:'#8db902', color:'#000', fontSize:'9px', fontWeight:800, padding:'2px 6px', borderRadius:'4px'}}>
                                                        {t.live}
                                                    </span>
                                                ) : (
                                                    <span style={{background:'#111', color:'#888', fontSize:'9px', fontWeight:600, padding:'2px 6px', borderRadius:'4px', border:'1px solid #222'}}>
                                                        {new Date(match.date!).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                </Link>
                            )
                        })}
                    </div>
                </div>
            ))
        )}
    </PageWrapper>
  )
}